import requests
from requests.auth import HTTPBasicAuth

RABBITMQ_API_URL = 'http://localhost:15672/api'
RABBITMQ_USER = 'admin'
RABBITMQ_PASSWORD = 'password'

def create_vhost(vhost_name):
    url = f'{RABBITMQ_API_URL}/vhosts/{vhost_name}'
    response = requests.put(url, auth=HTTPBasicAuth(RABBITMQ_USER, RABBITMQ_PASSWORD))
    if response.status_code == 204:
        print(f'Vhost {vhost_name} created successfully.')
    else:
        print(f'Failed to create vhost {vhost_name}: {response.content}')

def create_user(username, password):
    url = f'{RABBITMQ_API_URL}/users/{username}'
    data = {'password': password, 'tags': 'user'}
    response = requests.put(url, json=data, auth=HTTPBasicAuth(RABBITMQ_USER, RABBITMQ_PASSWORD))
    if response.status_code == 204:
        print(f'User {username} created successfully.')
    else:
        print(f'Failed to create user {username}: {response.content}')

def set_permissions(vhost_name, username):
    url = f'{RABBITMQ_API_URL}/permissions/{vhost_name}/{username}'
    data = {'configure': '.*', 'write': '.*', 'read': '.*'}
    response = requests.put(url, json=data, auth=HTTPBasicAuth(RABBITMQ_USER, RABBITMQ_PASSWORD))
    if response.status_code == 204:
        print(f'Permissions set successfully for user {username} on vhost {vhost_name}.')
    else:
        print(f'Failed to set permissions for user {username} on vhost {vhost_name}: {response.content}')

def configure_rabbitmq():
    tenants = {
        'app1': {'vhost': 'app1_vhost', 'user': 'app1_user', 'password': 'app1_password'},
        'app2': {'vhost': 'app2_vhost', 'user': 'app2_user', 'password': 'app2_password'},
        # Add more tenants here
    }

    for tenant, config in tenants.items():
        create_vhost(config['vhost'])
        create_user(config['user'], config['password'])
        set_permissions(config['vhost'], config['user'])

if __name__ == '__main__':
    configure_rabbitmq()